<?php
function paddingClasses($spacing){
    $section_classes = '';
    if ($spacing) {
        $spacing = get_sub_field('spacing');
        $classes = [];
        if (!empty($spacing['spacing_top'])) {
            $classes[] = 'pt-8 md:pt-12 lg:pt-18 xl:pt-20 2xl:pt-24';
        }
        if (!empty($spacing['spacing_bottom'])) {
            $classes[] = 'pb-8 md:pb-12 lg:pb-18 xl:pb-20 2xl:pb-24';
        }
        $section_classes = implode(' ', $classes);
    }
    return $section_classes;
}?>

<?php
function lighten_color($hex, $amount = 80) {
    $hex = ltrim($hex, '#');
    $r   = min(255, hexdec(substr($hex, 0, 2)) + $amount);
    $g   = min(255, hexdec(substr($hex, 2, 2)) + $amount);
    $b   = min(255, hexdec(substr($hex, 4, 2)) + $amount);
    return sprintf('#%02x%02x%02x', $r, $g, $b);
}

$base_color    = get_field('primary_color', 'option');
$second_color  = lighten_color($base_color, 80);
